#include <pthread.h>
#include <semaphore.h>

sem_t mutex;

void* thread_func(void* arg) {
 sem_wait(&mutex);
 // Critical Section
 sem_post(&mutex);
 return NULL;
}

int main() {
 sem_init(&mutex, 0, 1);
 pthread_t thread;
 pthread_create(&thread, NULL, thread_func, NULL);
 pthread_join(thread, NULL);
 sem_destroy(&mutex);
 return 0;
}
